import axios from "axios";
import { useEffect, useState } from "react";
import { toast } from "react-toastify";
import { config } from "../config";
import { extartError } from "../helper";

export default function usePostbyurl(url = "") {
  const [get_post, setPost] = useState(null);
  const [errors, setErrors] = useState(null);
  const [loading, setLoading] = useState(true);
  const [success, setSuccess] = useState(null);
  useEffect(() => {
    async function get_post_ajax() {
      try {
        const response = await axios.get(
          `${config.aps_rest_url}post_by_url?url=${url}`
        );
        const { success, message, data } = response;
        if (data) {
          setLoading(false);
          setSuccess(message);
          setPost(data);
        } else {
          setLoading(false);
          setErrors(message);
        }
      } catch (error) {
        console.warn(error);
        setLoading(false);
        setErrors(extartError(error));
      }
    }
    get_post_ajax();
  }, []);
  if (errors) {
    toast.error(errors);
  }
  return {
    get_post,
    errors,
    loading,
    setPost,
    setErrors,
    setLoading,
  };
}
