import axios from "axios";
import React, { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import { config } from "../app/config";
import { useAuth } from "../app/context/AuthContext";
import { mail_filter } from "../app/helper";
import Inputbox from "../components/Inputbox";
import Authimage from "./Authimage";

export default function () {
  useEffect(() => (document.title = "signup - " + config.app_title));
  const [errors, setErrors] = useState(null);
  const [email, setEmail] = useState("");
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [firstname, setFirstname] = useState("");
  const [lastname, setLastname] = useState("");
  const [loading, setLoading] = useState(false);
  const [checkterms, setTerms] = useState(true);

  const { setUser } = useAuth();

  const navigate = useNavigate();

  function clearinput() {
    setEmail("");
    setUsername("");
    setPassword("");
    setFirstname("");
    setLastname("");
  }

  function onSignup(e) {
    e.preventDefault();
    if (!username) {
      setErrors("Username is required!");
      return false;
    } else if (!email) {
      setErrors("Email is required!");
      return false;
    } else if (!mail_filter(email)) {
      setErrors("please enter a valid email address!");
      return false;
    } else if (password.length < 6) {
      setErrors("password should be at least 8 characters");
      return false;
    } else {
      setLoading(true);
      (async () => {
        try {
          const url = config.aps_rest_url + "signup";
          const _data = {
            username,
            email,
            password,
            firstname,
            lastname,
          };
          const response = await axios.post(url, { ..._data });
          const { success, message, user } = response.data;
          if (success) {
            setLoading(false);
            toast.success(message);
            clearinput();
            setTimeout(() => {
              window.location.reload();
            }, 2000);
          } else {
            setLoading(false);
            setErrors(message);
          }
        } catch (error) {
          setLoading(false);
          setErrors(error.response.data.message);
        }
      })();
    }
  }

  document.querySelectorAll(".entry.objProp").forEach(function (elm, i) {
    elm.click();
  });
  return (
    <div className="container-fluid justify-content-center">
      <div className="row h-100vh align-items-center background-white">
        <div className="col-md-6 text-center background-special h-100 align-middle p-0">
          <Authimage name="signup" />
        </div>
        <div className="col-md-6 h-100" id="login-responsive">
          <div className="card-body pr-10 pl-7 pt-10">
            <form method="POST" onSubmit={onSignup}>
              <h3 className="text-center font-weight-bold mb-8">
                Welcome Back to{" "}
                <span className="text-info">
                  <a href={config.app_url}>{config.app_name}</a>
                </span>
              </h3>

              <Inputbox
                classes="mb-4"
                lable="First Name"
                name={"firstname"}
                value={firstname}
                onChange={(e) => {
                  setFirstname(e.target.value);
                  setErrors(null);
                }}
              />
              <Inputbox
                classes="mb-4"
                lable="Last Name"
                name={"lastname"}
                value={lastname}
                onChange={(e) => {
                  setLastname(e.target.value);
                  setErrors(null);
                }}
              />
              <Inputbox
                classes="mb-4"
                lable="Username"
                value={username}
                name={"username"}
                onChange={(e) => {
                  setUsername(e.target.value);
                  setErrors(null);
                }}
              />
              <Inputbox
                classes="mb-4"
                lable="Email Address"
                type="email"
                value={email}
                name={"email"}
                onChange={(e) => {
                  setEmail(e.target.value);
                  setErrors(null);
                }}
              />
              <Inputbox
                classes="mb-4"
                lable="password"
                type="password"
                value={password}
                onChange={(e) => {
                  setPassword(e.target.value);
                  setErrors(null);
                }}
              />

              <div className="form-group mb-3 mt-3">
                <div className="d-flex">
                  <label className="custom-switch">
                    <input
                      type="checkbox"
                      className="custom-switch-input"
                      name="terms"
                      id="terms"
                      checked={checkterms}
                      onChange={() => setTerms(!checkterms)}
                    />
                    <span className="custom-switch-indicator" />
                    <span className="custom-switch-description">
                      Are, you agree to our{" "}
                      <Link to={"/terms-and-conditions"} className="text-info">
                        Terms and Conditions
                      </Link>{" "}
                      and{" "}
                      <Link to={"/privacy-policy"} className="text-info">
                        Privacy Policy
                      </Link>
                    </span>
                  </label>
                </div>
              </div>
              <div
                style={{ minHeight: "40px" }}
                className={
                  errors
                    ? "form-group text-white px-4 py-2 rounded bg-danger "
                    : "form-group text-white px-4 py-2 rounded "
                }
              >
                {errors}
              </div>
              <div className="form-group my-3">
                <button
                  disabled={loading}
                  type="submit"
                  className="btn btn-primary mr-2"
                >
                  {loading ? "loading.." : "Signup"}
                </button>
                <Link to={"/login"} className="btn btn-cancel">
                  login
                </Link>
              </div>
              <p
                className="fs-10 text-muted "
                style={{ marginTop: "50px" }}
              ></p>
            </form>
          </div>
          <footer className="footer" id="login-footer">
            <div className="container">
              <div className="row align-items-center">
                <div className="col-md-12 col-sm-12 fs-10 text-muted text-center">
                  Copyright © {new Date().getFullYear()}{" "}
                  <a href={config.app_url}>{config.app_name}</a>. All rights
                  reserved
                </div>
              </div>
            </div>
          </footer>
        </div>
      </div>
    </div>
  );
}
