import axios from "axios";
import React, { useContext, useEffect, useState } from "react";
import { toast } from "react-toastify";
import { config } from "../config";
import { extartError } from "../helper";

const AuthContex = React.createContext(null);

export function useAuth() {
  return useContext(AuthContex);
}

export default function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [errors, setErrors] = useState(null);
  const [loading, setLoading] = useState(true);
  const [success, setSuccess] = useState(null);

  useEffect(() => {
    async function get_user() {
      try {
        const response = await axios.post(`${config.aps_rest_url}user`);
        const { success, message, user } = response.data;
        if (success) {
          setLoading(false);
          setSuccess(message);
          setUser(user);
        } else {
          setLoading(false);
          setErrors(message);
        }
      } catch (error) {
        console.warn(error);
        setLoading(false);
        setErrors(extartError(error));
      }
    }
    get_user();
  }, []);

  if (errors) {
    toast.error(errors);
  }

  const value = {
    user,
    errors,
    loading,
    setUser,
    setErrors,
    setLoading,
  };

  return <AuthContex.Provider value={value}>{children}</AuthContex.Provider>;
}
