import React, { useEffect } from "react";
import ReactDOM from "react-dom";
import { BrowserRouter } from "react-router-dom";
import "./index.css";
import Router from "./Router";
//dependances
import aos from "aos";
import "aos/dist/aos.css";
import axios from "axios";
import { toast, ToastContainer } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
import { config } from "./app/config";
import AuthProvider from "./app/context/AuthContext";
import CustomerScript from "./app/CustomerScript";

function Index() {
  if (window.appsaeed.nonce) {
    axios.defaults.headers.common["X-WP-Nonce"] = window.appsaeed.nonce;
  } else {
    toast.error("somthing went wrong please contact to the developer");
  }
  useEffect(() => {
    aos.init();
    aos.refresh();
  }, []);
  return (
    <div className="page">
      <CustomerScript />
      <AuthProvider>
        <BrowserRouter basename={config.basename}>
          <ToastContainer />
          <Router />
        </BrowserRouter>
      </AuthProvider>
    </div>
  );
}

ReactDOM.render(<Index />, document.getElementById("app_root"));
