export const encrypt = (text, secret = "afj3ur932foiewfm") => {
  const textToChars = (text) => text.split("").map((c) => c.charCodeAt(0));
  const byteHex = (n) => ("0" + Number(n).toString(16)).substr(-2);
  const applySaltToChar = (code) =>
    textToChars(secret).reduce((a, b) => a ^ b, code);
  return text
    .split("")
    .map(textToChars)
    .map(applySaltToChar)
    .map(byteHex)
    .join("");
};

export const decrypt = (encoded, secret = "afj3ur932foiewfm") => {
  const textToChars = (text) => text.split("").map((c) => c.charCodeAt(0));
  const applySaltToChar = (code) =>
    textToChars(secret).reduce((a, b) => a ^ b, code);
  return encoded
    .match(/.{1,2}/g)
    .map((hex) => parseInt(hex, 16))
    .map(applySaltToChar)
    .map((charCode) => String.fromCharCode(charCode))
    .join("");
};

export function setCookie(cname, cvalue, exdays = 30, path = "/") {
  const value = JSON.stringify({
    cvalue,
    exdays,
    path,
  });
  const d = new Date();
  d.setTime(d.getTime() + exdays * 24 * 60 * 60 * 1000);
  const expires = "expires=" + d.toUTCString();
  document.cookie =
    cname +
    "=" +
    btoa(value) +
    ";" +
    expires +
    ";SameSite=None; Secure;path=" +
    path;
}

export function getCookie(cname, callback = () => {}) {
  try {
    const name = cname + "=";
    const decodedCookie = decodeURIComponent(document.cookie);
    const ca = decodedCookie.split(";");
    for (let i = 0; i < ca.length; i++) {
      let c = ca[i];
      while (c.charAt(0) === " ") {
        c = c.substring(1);
      }
      if (c.indexOf(name) === 0) {
        return JSON.parse(atob(c.substring(name.length, c.length))).cvalue;
      }
    }
  } catch (err) {
    callback(null, err);
    return false;
  }
  return false;
}

export const cookies = document.cookie
  .split(";")
  .map((c) => ({ name: c.split("=")[0], value: c.split("=")[1] }));

//
export function getCookies() {
  const _cookies = [];
  const cookieArr = document.cookie.split(";");
  for (var i = 0; i < cookieArr.length; i++) {
    const cookiePair = cookieArr[i].split("=");
    _cookies.push({
      name: cookiePair[0].trim(),
      value: decodeURIComponent(cookiePair[1]),
    });
  }
  return cookies;
}

//check cookie
export const isCookie = (cname) => (getCookie(cname) ? true : false);

//remove cookie
export const rmCookie = (cname) => (document.cookie = cname + "=; Max-Age=0");

//load script
export function loadScript(id, url, callback, onError) {
  const element = document.getElementsByTagName("script")[0];
  const fjs = element;
  let js = element;
  js = document.createElement("script");
  js.id = id;
  js.src = url;
  if (fjs && fjs.parentNode) {
    fjs.parentNode.insertBefore(js, fjs);
  } else {
    document.head.appendChild(js);
  }
  js.onerror = onError;
  js.onload = callback;
}

export function removeScript(id) {
  const element = document.getElementById(id);
  if (element) {
    element.parentNode.removeChild(element);
  }
}

export const objectToStr = (message) => {
  let msg = "";
  if (typeof message === "object") {
    for (const key in message) {
      msg += `${key}: ${message[key]}`;
    }
  } else {
    msg = String(message);
  }
  return msg;
};

export function extartError(error) {
  let message = "";
  try {
    if (typeof error === "string") {
      message = error;
    } else if (error?.response?.data?.message) {
      message = error?.response?.data?.message;
    } else if (error?.response?.data) {
      message = error?.response?.data;
    } else if (error?.response) {
      message = error?.response;
    } else {
      message = error;
    }
  } catch (er) {
    message = er;
  }
  return objectToStr(message);
}

export function mail_filter($email) {
  return /^\w+([\.-]?\w+)*@\w+([\.-]?\w+)*(\.\w{2,3})+$/.test($email);
}

