import { useEffect } from "react";
import { Link } from "react-router-dom";
import { textcontent } from "../../app/content";
import { useAuth } from "../../app/context/AuthContext";
import Typed from "../../libs/typed/Typed";

export default function () {
  const { user, loading } = useAuth();
  const type_id = "bannar_typed";
  useEffect(() => {
    let _typed = null;
    if (document.querySelector(`#${type_id}`)) {
      _typed = new Typed(`#${type_id}`, {
        strings: textcontent.herosection.typing,
        typeSpeed: 40,
        backSpeed: 40,
        backDelay: 2000,
        loop: true,
        showCursor: false,
      });
    }
    return () => _typed;
  }, []);

  return (
    <section id="main-wrapper">
      <div
        style={{
          backgroundImage: `url(${textcontent.herosection.bgImage})`,
          backgroundAttachment: "fixed",
          backgroundSize: "cover",
          backgroundRepeat: "no-repeat",
        }}
        className="h-100vh justify-center min-h-screen"
        id="main-background"
      >
        <div className="container h-100vh ">
          <div className="row h-100vh vertical-center">
            <div className="col-sm-12 upload-responsive">
              <div className="text-container text-center">
                <h3
                  className="mb-4 font-weight-bold text-white"
                  data-aos="fade-left"
                  data-aos-delay={400}
                  data-aos-once="true"
                  data-aos-duration={700}
                >
                  {textcontent.herosection.welcome}
                </h3>
                <h1
                  className=" text-white"
                  data-aos="fade-left"
                  data-aos-delay={500}
                  data-aos-once="true"
                  data-aos-duration={700}
                >
                  {textcontent.herosection.title}
                </h1>

                <h1
                  className=" mb-0 gradient fixed-height"
                  id={type_id}
                  data-aos="fade-left"
                  data-aos-delay={600}
                  data-aos-once="true"
                  data-aos-duration={900}
                />
                <p
                  className="fs-18 text-white"
                  data-aos="fade-left"
                  data-aos-delay={700}
                  data-aos-once="true"
                  data-aos-duration={1100}
                >
                  {textcontent.herosection.description}
                </p>
                <Hearhard />
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

function Hearhard() {
  const { user, loading } = useAuth();
  if (!loading) {
    if (user) {
      return (
        <Link
          to={"/dashboard"}
          className="btn btn-success special-action-button"
          data-aos="fade-left"
          data-aos-delay={800}
          data-aos-once="true"
          data-aos-duration={1100}
        >
          Got to dashboard
        </Link>
      );
    } else {
      return (
        <Link
          to={"/signup"}
          className="btn special-action-button"
          style={{ background: "#D84727" }}
          data-aos="fade-left"
          data-aos-delay={800}
          data-aos-once="true"
          data-aos-duration={1100}
        >
          Try Now For Free
        </Link>
      );
    }
  }
  return null;
}
