import axios from "axios";
import React, { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import { config } from "../app/config";
import Inputbox from "../components/Inputbox";
import Authimage from "./Authimage";
export default function () {
  const navigate = useNavigate();
  useEffect(() => (document.title = "login - " + config.app_title));
  const [errors, setErrors] = useState(null);
  const [_loading, _setLoading] = useState(false);
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [remember, setRemember] = useState(true);

  function clearinput() {
    setUsername("");
    setPassword("");
  }

  function onLogin(e) {
    e.preventDefault();
    if (!username) {
      setErrors("Username or email is required!");
      return false;
    } else if (!password) {
      setErrors("empty password!");
      return false;
    } else {
      _setLoading(true);
      (async () => {
        try {
          const url = config.aps_rest_url + "login";
          const _data = {
            username: username.trim(),
            password: password,
            remember: remember,
          };
          const response = await axios.post(url, { ..._data });
          const { success, message, user } = response.data;
          if (success) {
            _setLoading(false);
            toast.success(message);
            clearinput();
            setTimeout(() => {
              navigate("/");
            }, 2000);
          } else {
            _setLoading(false);
            setErrors(message);
          }
        } catch (error) {
          _setLoading(false);
          setErrors(error.response?.data.message);
        }
      })();
    }
  }

  return (
    <div className="container-fluid justify-content-center">
      <div className="row h-100vh align-items-center background-white">
        <div className="col-md-6 text-center background-special h-100 align-middle p-0">
          <Authimage name="login" />
        </div>
        <div className="col-md-6 h-100" id="login-responsive">
          <div className="card-body pr-10 pl-10 pt-10">
            <form method="POST" action="#" onSubmit={onLogin}>
              <h3 className="text-center font-weight-bold mb-8">
                Welcome Back to{" "}
                <span className="text-info">
                  <Link to={"/"}>{config.app_name}</Link>
                </span>
              </h3>

              <Inputbox
                classes="mb-4"
                lable="Username or email address"
                name={"username"}
                type="text"
                value={username}
                onChange={(e) => {
                  setUsername(e.target.value);
                  setErrors(null);
                }}
              />
              <Inputbox
                classes="mb-4"
                lable="Your password"
                name={"password"}
                type="password"
                value={password}
                onChange={(e) => {
                  setPassword(e.target.value);
                  setErrors(null);
                }}
              />

              <div className="form-group mb-3">
                <div className="d-flex">
                  <label className="custom-switch">
                    <input
                      type="checkbox"
                      className="custom-switch-input"
                      name="remember"
                      id="remember"
                      checked={remember}
                      onChange={() => setRemember(!remember)}
                    />
                    <span className="custom-switch-indicator" />
                    <span className="custom-switch-description">
                      Keep me logged in
                    </span>
                  </label>
                  <div className="ml-auto">
                    <a
                      className="text-info fs-12"
                      href={config.app_url + "forgot-password"}
                    >
                      Forgot Your Password?
                    </a>
                  </div>
                </div>
              </div>
              <div
                style={{ minHeight: "40px" }}
                className={
                  errors
                    ? "form-group text-white px-4 py-2 rounded bg-danger "
                    : "form-group text-white px-4 py-2 rounded "
                }
                dangerouslySetInnerHTML={{ __html: errors }}
              ></div>
              <div className="form-group my-3">
                <button
                  disabled={_loading}
                  type="submit"
                  className="btn btn-primary mr-2"
                >
                  Login
                </button>
                <Link to={"/signup"} className="btn btn-cancel">
                  Sign Up
                </Link>
              </div>
              <p className="fs-10 text-muted pt-3">
                By continuing, you agree to our{" "}
                <a
                  href={config.app_url + "terms-and-conditions"}
                  className="text-info"
                >
                  Terms and Conditions
                </a>{" "}
                and{" "}
                <a
                  href={config.app_url + "privacy-policy"}
                  className="text-info"
                >
                  Privacy Policy
                </a>
              </p>
            </form>
          </div>
          <footer className="footer" id="login-footer">
            <div className="container">
              <div className="row align-items-center">
                <div className="col-md-12 col-sm-12 fs-10 text-muted text-center">
                  Copyright © {new Date().getFullYear()}{" "}
                  <a href={config.app_url}>{config.app_name}</a>. All rights
                  reserved
                </div>
              </div>
            </div>
          </footer>
        </div>
      </div>
    </div>
  );
}
