import { Link } from "react-router-dom";
import { config } from "../../app/config";
import { useAuth } from "../../app/context/AuthContext";
export default function Navbar() {
  const { user } = useAuth();
  return (
    <nav
      className="navbar navbar-expand-lg navbar-light w-100"
      id="navbar-responsive"
    >
      <a className="navbar-brand" href={config.app_url}>
        <img
          style={{ height: "36px" }}
          id="brand-img"
          src={config.app_icon}
          alt="favicon"
        />
      </a>
      <button
        className="navbar-toggler"
        type="button"
        data-bs-toggle="collapse"
        data-bs-target="#navbarNav"
        aria-controls="navbarNav"
        aria-expanded="false"
        aria-label="Toggle navigation"
      >
        <span className="navbar-toggler-icon" />
      </button>
      <div className="collapse navbar-collapse section-links" id="navbarNav">
        <ul className="navbar-nav">
          <MenuItem
            name="Home"
            url={"#main-wrapper"}
            linkclass="nav-link scroll active"
          />
          <MenuItem
            name="prices"
            url={"#prices-wrapper"}
            linkclass="nav-link scroll"
          />
          <MenuItem
            name="features"
            url={"#features"}
            linkclass="nav-link scroll"
          />
          <MenuItem
            name="faqs"
            url={"#faq-wrapper"}
            linkclass="nav-link scroll"
          />
          <MenuItem
            name="contact us"
            url={"#contact-wrapper"}
            linkclass="nav-link scroll"
          />
          {!user ? (
            <>
              <MenuItem
                async={true}
                name="login"
                url={"/login"}
                linkclass="btn btn-primary special-action-button"
              />
              <MenuItem
                async={true}
                name="signup"
                url={"/signup"}
                linkclass="ml-3 action-button register-button"
              />
            </>
          ) : (
            <MenuItem
              async={true}
              name="Dashboard"
              url={"/dashboard"}
              linkclass="ml-3 action-button dashboard-button"
            />
          )}
        </ul>
      </div>
    </nav>
  );
}

export const MenuItem = ({
  async = false,
  name = "",
  url,
  classes = "",
  linkclass = "",
  children,
  ...arg
}) => {
  return (
    <li {...arg} className={"nav-item " + classes}>
      {async ? (
        <Link to={url} className={"  " + linkclass}>
          {children ? children : name}
        </Link>
      ) : (
        <a href={config.app_url + url} className={"  " + linkclass}>
          {children ? children : name}
        </a>
      )}
    </li>
  );
};
